const fs=require("fs"),newLineRegex=/\r?\n/;function sort(e,t){return e.map(e=>{for(const n of t)if(n.regex.test(e))return{path:e,weight:n.weight};return{path:e,weight:10}}).sort((e,t)=>t.weight-e.weight).map(e=>e.path)}function canAccess(e){if(!e)return!1;try{return fs.accessSync(e),!0}catch(e){return!1}}function isExecutable(e){if(!e)return!1;try{var t=fs.statSync(e);return t&&"function"==typeof t.isFile&&t.isFile()}catch(e){return!1}}module.exports={sort:sort,canAccess:canAccess,isExecutable:isExecutable,newLineRegex:newLineRegex};